class PaymentSecurity {
  PaymentSecurity._();

  static void assertNoCardDataStored(Map<String, dynamic> payload) {
    final s = jsonEncode(payload).toLowerCase();
    final forbidden = <String>[
      'cardnumber',
      'pan',
      'cvc',
      'cvv',
      'expiry',
      'expmonth',
      'expyear',
      'track1',
      'track2',
      'magstripe',
    ];
    for (final f in forbidden) {
      if (s.contains(f)) {
        throw PaymentException('pci_violation', 'Payload appears to contain prohibited card data: $f');
      }
    }
  }
}

